fetch_bogie_no_on_mount.body:
// Helper to wait until e.args is available
const waitForArgs = async (timeout = 2000, interval = 50) => {
    const start = Date.now();
    while (Date.now() - start < timeout) {
        if (e.args && Array.isArray(e.args) && e.args.length > 0) {
            return e.args;
        }
        await new Promise(resolve => setTimeout(resolve, interval));
    }
    return null;
};

// ---------------------------------------------------------
// UNHANDLED REJECTION HANDLER
// ---------------------------------------------------------
Promise.resolve().then(async () => {

    const rawArgs = await waitForArgs();

    if (!rawArgs) {
        console.warn("Action: e.args was not available within timeout.");
        return;
    }

    // CRITICAL: Extract Primitives ONLY to avoid circular structure errors
    const searchValue = (rawArgs[0] != null) ? String(rawArgs[0]) : "";
    const loadCallback = (typeof rawArgs[1] === 'function') ? rawArgs[1] : null;
    const currentDataLength = (typeof rawArgs[2] === 'number') ? rawArgs[2] : 0;

    if (currentDataLength > 0) {
        if (loadCallback) loadCallback([]);
        return;
    }

    const now = Date.now();
    // Renamed to _bogieFetching to match _bogieDataLookup context
    if (window._lastBogieCallTime && (now - window._lastBogieCallTime) < 500) {
        return;
    }
    window._lastBogieCallTime = now;

    if (window._bogieFetching) {
        return;
    }
    window._bogieFetching = true;

    let savedToken = localStorage.getItem('dlms_auth_token');

    if (!savedToken) {
        window._bogieFetching = false;
        if (loadCallback) loadCallback([]);
        return;
    }

    let requestBody = {
        "fields": ["data.main.data"],
        "search": "",
        "status": "pending",
        "limit": 100
    };

    try {
        const res = await fetch('https://dlms-api.iotnp.com/api/v1/templates/dispatch_memo_operational/dropdown/v2', {
            method: 'POST',
            headers: {
                'accept': 'application/json',
                'Content-Type': 'application/json',
                'Authorization': `Bearer ${savedToken}`
            },
            body: JSON.stringify(requestBody)
        });

        if (!res.ok) {
            window._bogieFetching = false;
            if (loadCallback) loadCallback([]);
            return;
        }

        const response = await res.json();
        const items = Array.isArray(response.data) ? response.data : [];

        const getMainData = (item) => {
            if (item["data.main.data"]) return item["data.main.data"];
            if (item.main?.data) return item.main.data;
            return null;
        };

        // Initialize lookup map for bogie data
        if (!window._bogieDataLookup) {
            window._bogieDataLookup = new Map();
        }

        const uniqueMap = new Map();
        items.forEach(item => {
            const mainData = getMainData(item);
            const assemblyName = mainData?.parent_data__assembly__label || "Unnamed Item";
            const bogieId = mainData?.parent_data__bogie_id || "";
            const castings = mainData?.parent_data__castings || null;

            // Only add to the map if bogieId exists AND castings data is available
            if (bogieId && castings && Object.keys(castings).length > 0) {
                if (!uniqueMap.has(item._id)) {
                    // Store in lookup map for later use
                    window._bogieDataLookup.set(bogieId, {
                        _id: item._id,
                        assembly_name: assemblyName,
                        bogie_id: bogieId,
                        castings: castings,
                        selected_assembly_id: mainData?.parent_data__selected_assembly_id || "",
                        created_at: mainData?.created_at || ""
                    });

                    uniqueMap.set(item._id, {
                        value: bogieId,
                        label: `${assemblyName} - ${bogieId}`,
                        id: item._id,
                        data: {
                            _id: item._id,
                            assembly_name: assemblyName,
                            bogie_id: bogieId,
                            castings: castings,
                            selected_assembly_id: mainData?.parent_data__selected_assembly_id || "",
                            created_at: mainData?.created_at || "",
                            _mainData: mainData
                        }
                    });
                }
            }
        });

        const preparedData = [...uniqueMap.values()];

        window._bogieFetching = false;

        if (e.setUserDefinedProps) {
            e.setUserDefinedProps({ data: preparedData });
        }

        if (loadCallback) {
            loadCallback([]);
        }

    } catch (err) {
        window._bogieFetching = false;
        console.error("Dropdown fetch error:", err);
        if (loadCallback) loadCallback([]);
    }

}).catch((err) => {
    // ---------------------------------------------------------
    // HANDLER FOR UNHANDLED PROMISE REJECTION
    // ---------------------------------------------------------
    console.error("Caught Unhandled Promise Rejection in Action:", err);
    window._bogieFetching = false;
});

on_change_assembly.body:
const selectedValues = e.args[0] || [];

if (!window._bogieDataLookup) {
    window._bogieDataLookup = new Map();
}

for (let i = 0; i < 70; i++) {
    e.data[`dm__bogie__${i}__id`] = "";
    e.data[`dm__bogie__${i}__no`] = "";
    e.data[`dm__bogie__${i}__assembly`] = "";
    for (let j = 0; j < 6; j++) {
        e.data[`dm__bogie__${i}__casting__${j}__name`] = "";
        e.data[`dm__bogie__${i}__casting__${j}__serials`] = "";
    }
}

for (let j = 0; j < 6; j++) {
    e.data[`dm__casting_header__${j}`] = "";
}

e.data.selected_bogies_count = 0;
e.data.all_casting_names = [];
e.data.selected_bogie_ids = [];

if (!Array.isArray(e.data.assembly_bogieid_bogieno_map)) {
    e.data.assembly_bogieid_bogieno_map = [];
}

if (selectedValues.length === 0) {
    e.data.assembly = [];
    e.data.assembly_bogieid_bogieno_map = [];
    return;
}

// Remove entries where bogie_id is no longer selected
e.data.assembly_bogieid_bogieno_map = e.data.assembly_bogieid_bogieno_map.filter(
    entry => selectedValues.includes(entry.bogie_id)
);

// Build a lookup of previously saved bogie_no values before we rebuild
const prevBogieNoMap = {};
e.data.assembly_bogieid_bogieno_map.forEach(entry => {
    if (entry.bogie_id) {
        prevBogieNoMap[entry.bogie_id] = entry.bogie_no || "";
    }
});

const allCastingNames = new Set();
const bogieDataArray = [];
const selected_bogie_document_ids = [];

selectedValues.forEach(bogieId => {
    const bogieData = window._bogieDataLookup.get(bogieId);
    if (bogieData && bogieData.castings) {
        Object.keys(bogieData.castings).forEach(castingName => {
            allCastingNames.add(castingName);
        });
        bogieDataArray.push(bogieData);
    }
    if (bogieData) selected_bogie_document_ids.push(bogieData._id);
});

const castingNamesArray = [...allCastingNames].slice(0, 6);
e.data.all_casting_names = castingNamesArray;
e.data.selected_bogies_count = bogieDataArray.length;
e.data.selected_bogie_ids = selectedValues;
e.data.selected_bogie_document_ids = selected_bogie_document_ids;

for (let j = 0; j < 6; j++) {
    e.data[`dm__casting_header__${j}`] = castingNamesArray[j] || "";
}

bogieDataArray.forEach((bogieData, rowIdx) => {
    if (rowIdx < 70) {
        e.data[`dm__bogie__${rowIdx}__id`] = bogieData.bogie_id || "";
        e.data[`dm__bogie__${rowIdx}__assembly`] = bogieData.assembly_name || "";
        e.data[`dm__bogie__${rowIdx}__no`] = prevBogieNoMap[bogieData.bogie_id] || "";

        castingNamesArray.forEach((castingName, colIdx) => {
            const castingData = bogieData.castings[castingName];
            if (castingData) {
                e.data[`dm__bogie__${rowIdx}__casting__${colIdx}__name`] = castingName;
                e.data[`dm__bogie__${rowIdx}__casting__${colIdx}__serials`] =
                    (castingData.serialNumbers || []).join(", ");
            } else {
                e.data[`dm__bogie__${rowIdx}__casting__${colIdx}__name`] = "";
                e.data[`dm__bogie__${rowIdx}__casting__${colIdx}__serials`] = "-";
            }
        });

        // Remove old entry for this bogie_id if present
        e.data.assembly_bogieid_bogieno_map = e.data.assembly_bogieid_bogieno_map.filter(
            entry => entry.bogie_id !== bogieData.bogie_id
        );

        // Build castings array
        const castingsForMap = [];
        castingNamesArray.forEach((castingName, colIdx) => {
            const nameVal = e.data[`dm__bogie__${rowIdx}__casting__${colIdx}__name`];
            const serialsVal = e.data[`dm__bogie__${rowIdx}__casting__${colIdx}__serials`];
            if (nameVal) {
                castingsForMap.push({ name: nameVal, serials: serialsVal });
            }
        });

        e.data.assembly_bogieid_bogieno_map.push({
            row_no: rowIdx,
            assembly: bogieData.assembly_name || "",
            bogie_id: bogieData.bogie_id || "",
            bogie_no: prevBogieNoMap[bogieData.bogie_id] || "",
            dm_no: e.data.dm_no || "",
            castings: castingsForMap
        });
    }
});

console.log("Assembly selection changed:", {
    selectedCount: bogieDataArray.length,
    castingColumns: castingNamesArray,
    bogies: bogieDataArray,
    assembly_bogieid_bogieno_map: e.data.assembly_bogieid_bogieno_map
});

