formValidator:
const errors = {};


console.log("is rejecting",window.__FORM_IS_REJECTING__);
if (window.__FORM_IS_REJECTING__) {
    if (!formData.remarks || formData.remarks.toString().trim() === '') {
        errors['remarks'] = 'Remarks is required when rejecting';
    }
}

const hasValue = (val) => {
    return val !== null && val !== undefined && val !== '';
};

// Bogie ID and Bogie No validation (up to 80 rows)
for (let i = 1; i <= 80; i++) {
    const bogieIdKey = `bogie_row_${i}_id`;
    const bogieNoKey = `bogie_row_${i}_no`;

    const bogieIdValue = formData[bogieIdKey];
    const bogieNoValue = formData[bogieNoKey];

    // If bogie_id exists, bogie_no is mandatory
    if (hasValue(bogieIdValue) && !hasValue(bogieNoValue)) {
        errors[bogieNoKey] = `Bogie No is required for Bogie ID: ${bogieIdValue}`;
    }
}

return Object.keys(errors).length > 0 ? errors : undefined;

